def evaluate_experts(experts):
    # Calculate the weighted sum of verdicts
    weighted_sum = sum(expert['weight'] * (1 if expert['verdict'] == 'True' else 0) for expert in experts)

    # Calculate the total weight
    total_weight = sum(expert['weight'] for expert in experts)

    # Calculate the weighted average
    weighted_average = weighted_sum / total_weight

    # Determine the verdict based on the weighted average
    if weighted_average >= 0.5:
        verdict = 'True'
    else:
        verdict = 'False'

    # Determine the explanation
